{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://game-omni/spec/classification.schema.json",
  "title": "W0 Classification artifact",
  "description": "The single artifact written by the W0 Classify node (spec/classification.json). Routes the whole game-omni pipeline: physics-first archetype, one-line core loop, and explicit scope-cut. Authored by packages/skills/classify-game/SKILL.md.",
  "type": "object",
  "additionalProperties": false,
  "required": [
    "prompt",
    "archetype",
    "coreLoop",
    "coreVerb",
    "physicsProfile",
    "reasoning",
    "confidence",
    "scoringModel",
    "scopeCut"
  ],
  "properties": {
    "prompt": {
      "type": "string",
      "minLength": 1,
      "description": "The raw args.prompt, copied verbatim. Provenance for every downstream node."
    },
    "archetype": {
      "type": "string",
      "minLength": 1,
      "description": "must resolve in templates/genres.json archetypes[]"
    },
    "coreLoop": {
      "type": "string",
      "minLength": 1,
      "description": "One self-enclosed sentence: player verb + goal/win + obstacle + fail/reset. The spine W1 elaborates and the seed for W1 win/lose."
    },
    "coreVerb": {
      "type": "string",
      "minLength": 1,
      "description": "The single central player verb (e.g. jump, push, place tower)."
    },
    "physicsProfile": {
      "type": "object",
      "additionalProperties": false,
      "required": ["hasGravity", "perspective", "movementType"],
      "description": "The structured physics that justifies the archetype (auditable, drives W2 engine params).",
      "properties": {
        "hasGravity": {
          "type": "boolean",
          "description": "True essentially only for platformer."
        },
        "perspective": {
          "type": "string",
          "enum": ["side", "top_down", "none"]
        },
        "movementType": {
          "type": "string",
          "enum": ["continuous", "grid", "path", "ui_only"]
        }
      }
    },
    "reasoning": {
      "type": "string",
      "minLength": 1,
      "description": "1-2 sentences: which physics KEY QUESTION decided the archetype. On low confidence, names the ambiguity / runner-up."
    },
    "confidence": {
      "type": "string",
      "enum": ["high", "medium", "low"],
      "description": "high = unambiguous; medium = resolved via tie-break; low = barely fit / defaulted (see SKILL §5)."
    },
    "scoringModel": {
      "type": "string",
      "enum": ["none", "bounded-collectible", "bounded-threshold", "performance"],
      "description": "The scoring signal derived from the prompt's GOAL-TYPE (SKILL §2.5), passed to W1 so it scores only when the type warrants it (never a reflexive open counter). none = pure completion, no countable rewards (win is the readout); bounded-collectible = completion via a finite reward set (maxScore = sum of rewards); bounded-threshold = hit a target/wave/opponent; performance = score-attack, the number IS the goal. Completion prompts default to none/bounded-collectible, never performance."
    },
    "scopeCut": {
      "type": "array",
      "minItems": 1,
      "items": { "type": "string", "minLength": 1 },
      "description": "What is deliberately OUT of v1 (4-8 entries recommended). The anti-slop guardrail; downstream treats these as out-of-bounds. Names systems, not one-off named features. Never cuts game-feel/juice. Distinguishes 'more systems' (cut) from 'a short engine-reuse level-ladder' (kept — SKILL §3 scope-preserve)."
    },
    "mustPreserve": {
      "type": "string",
      "description": "The scope-PRESERVE counter-pressure (SKILL §3): the ONE core contested decision (a risk weighed against a reward on the critical path) the scope-cut must NOT remove, so W1 keeps round one a real game, not a tutorial. A relation in one line, never a per-prompt constant. Omit only for a pure sandbox prompt with no contested decision."
    },
    "coreFantasy": {
      "type": "string",
      "description": "Optional <=8-word emotional hook. Helps W1 + W3. Omit if not obvious."
    },
    "lowConfidence": {
      "type": "boolean",
      "description": "Optional convenience boolean mirroring confidence=='low'. The canonical signal is the confidence enum; emit this only if a consumer wants a plain boolean."
    }
  }
}

bash.command:
node -e "
const c=require('./out/e2e-m3/spec/classification.json');
// Validate against the schema (manual structural check since no ajv handy)
const required=['prompt','archetype','coreLoop','coreVerb','physicsProfile','reasoning','confidence','scoringModel','scopeCut'];
for(const k of required){ if(!(k in c)){ console.error('MISSING',k); process.exit(1);} }
const pp=c.physicsProfile;
if(typeof pp.hasGravity!=='boolean'){console.error('hasGravity bad');process.exit(1);}
if(!['side','top_down','none'].includes(pp.perspective)){console.error('perspective bad');process.exit(1);}
if(!['continuous','grid','path','ui_only'].includes(pp.movementType)){console.error('movementType bad');process.exit(1);}
if(!['high','medium','low'].includes(c.confidence)){console.error('confidence bad');process.exit(1);}
if(!['none','bounded-collectible','bounded-threshold','performance'].includes(c.scoringModel)){console.error('scoringModel bad');process.exit(1);}
if(!Array.isArray(c.scopeCut)||c.scopeCut.length<1){console.error('scopeCut empty');process.exit(1);}
console.log('schema ok');
"

