 * engine sub-steps the ball at `speed` so a fast serve never tunnels (RB §2.2).
 */
export interface BallData {
  id?: string;
  /** CENTER x of the ball's start (typically just above the paddle). */
  x: number;
  /** CENTER y of the ball's start. */
  y: number;
